module top_module(output reg flag, input din, clk, rst_n);reg [2:0] data_buffer;
always @(negedge clk)
begin
  if(rst_n==1'b0)
  begin
    data_buffer = 3'bx;
    flag = 1'b0;
  end
  else
  begin
    if({data_buffer, din}==4'b1101 || {data_buffer, din}==4'b0110)
      flag = 1'b1;
    else
      flag = 1'b0;
    data_buffer = {data_buffer[1:0], din};
  end
end
endmodule
